import type { AttachmentData } from '../attachments/attachment.types';

export type PromptInputState = 'ready' | 'submitted' | 'streaming' | 'error';

export type PromptInputSize = 'sm' | 'md' | 'lg';

export type PromptInputVariant = 'default' | 'ghost' | 'bordered';

export interface PromptInputSubmitEvent {
  value: string;
  attachments: readonly AttachmentData[];
  preventDefault: () => void;
}

export interface PromptInputAttachmentError {
  file: File;
  reason: 'invalid-mime' | 'too-large' | 'max-count';
  message: string;
}

export interface PromptInputModelOption {
  id: string;
  label: string;
  description?: string;
  badge?: string;
  disabled?: boolean;
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  HostListener,
  inject,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';
import { cn } from '@gremorie/ng-core';
import { toAttachmentData } from '../attachments/attachment.utils';
import type { AttachmentData } from '../attachments/attachment.types';

import {
  PromptInputAttachmentError,
  PromptInputSize,
  PromptInputState,
  PromptInputSubmitEvent,
  PromptInputVariant,
} from './prompt-input.types';

/**
 * The React composer card is `InputGroup` (rx-forms) + the rx-ai overrides
 * `overflow-hidden rounded-xl bg-card dark:bg-card`. The class string below is
 * the same InputGroup base, with the layout that React derives from
 * `has-[>[data-align=block-*]]` selectors resolved statically (`h-auto
 * flex-col items-stretch`) because the Angular column always hosts block
 * addon rows. Keep it in lock-step with
 * `packages/rx-forms/src/lib/input-group/input-group.tsx` +
 * `packages/rx-ai/src/lib/prompt-input/prompt-input.tsx`.
 */
const INPUT_GROUP_CARD =
  'group/input-group border-input dark:bg-input/30 shadow-xs relative flex w-full rounded-md border outline-none transition-[color,box-shadow] h-auto flex-col items-stretch has-[[data-slot=input-group-control]:focus-visible]:ring-ring has-[[data-slot=input-group-control]:focus-visible]:ring-1 has-[[data-slot][aria-invalid=true]]:ring-destructive/20 has-[[data-slot][aria-invalid=true]]:border-destructive dark:has-[[data-slot][aria-invalid=true]]:ring-destructive/40 overflow-hidden rounded-xl bg-card dark:bg-card';

const containerVariants = cva(INPUT_GROUP_CARD, {
  variants: {
    size: {
      // `md` is the React reference rendering (no extra text class on the
      // card; rows and textarea set their own type scale).
      sm: 'text-sm',
      md: '',
      lg: 'text-base',
    },
    variant: {
      default: '',
      ghost: 'border-transparent bg-transparent shadow-none',
      bordered: 'border-2',
    },
    state: {
      ready: '',
      submitted: '',
      streaming: '',
      error: 'border-destructive',
    },
  },
  defaultVariants: {
    size: 'md',
    variant: 'default',
    state: 'ready',
  },
});

@Component({
  selector: 'prompt-input',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <ng-content />
    <span class="sr-only" aria-live="polite" aria-atomic="true">{{
      statusAnnouncement()
    }}</span>
  `,
  host: {
    role: 'form',
    '[class]': 'hostClass()',
    '[attr.aria-label]': 'ariaLabel()',
    '[attr.aria-disabled]': 'disabled() ? "true" : null',
    '[attr.data-state]': 'state()',
    '[attr.data-disabled]': 'disabled() ? "" : null',
    '[attr.data-dragging]': 'isDragging() ? "" : null',
    '(keydown)': 'handleKeydown($event)',
    '(dragover)': 'handleDragOver($event)',
    '(dragenter)': 'handleDragEnter($event)',
    '(dragleave)': 'handleDragLeave($event)',
    '(drop)': 'handleDrop($event)',
  },
})
export class PromptInput {
  private readonly elementRef: ElementRef<HTMLElement> = inject(ElementRef);

  readonly value = model<string>('');
  readonly attachments = model<readonly AttachmentData[]>([]);

  readonly state = input<PromptInputState>('ready');
  readonly size = input<PromptInputSize>('md');
  readonly variant = input<PromptInputVariant>('default');
  readonly disabled = input<boolean>(false);
  readonly submitOnEnter = input<boolean>(true);
  readonly ariaLabel = input<string>('AI prompt input');

  /**
   * When `false`, file attachments are disabled (drag-drop and paste ignored).
   * Otherwise, an array of MIME patterns (`image/*`, `application/pdf`, etc.)
   * that are accepted.
   */
  readonly acceptAttachments = input<readonly string[] | false>(false);
  readonly maxAttachments = input<number>(10);
  readonly maxAttachmentSize = input<number>(10 * 1024 * 1024); // 10MB

  readonly submitted = output<PromptInputSubmitEvent>();
  readonly canceled = output<void>();
  readonly retried = output<void>();
  readonly attachmentError = output<PromptInputAttachmentError>();

  private readonly dragCounter = signal(0);

  readonly isDragging = computed(() => this.dragCounter() > 0);

  readonly attachmentsEnabled = computed(() => {
    const accept = this.acceptAttachments();
    return accept !== false && !this.disabled();
  });

  readonly statusAnnouncement = computed(() => {
    switch (this.state()) {
      case 'submitted':
        return 'Message submitted. Waiting for response.';
      case 'streaming':
        return 'AI is responding.';
      case 'error':
        return 'Submission failed. Press the button to retry.';
      default:
        return '';
    }
  });

  readonly hostClass = computed(() =>
    cn(
      containerVariants({
        size: this.size(),
        variant: this.variant(),
        state: this.state(),
      }),
      this.disabled() && 'pointer-events-none opacity-50',
      this.isDragging() && 'ring-2 ring-ring ring-offset-2',
    ),
  );

  handleKeydown(event: KeyboardEvent): void {
    if (this.disabled()) {
      return;
    }

    const isEnter = event.key === 'Enter';
    const isMod = event.metaKey || event.ctrlKey;

    if (isEnter && isMod) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (isEnter && !event.shiftKey && this.submitOnEnter()) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      this.handleEscape();
    }
  }

  @HostListener('document:keydown', ['$event'])
  handleGlobalKeydown(event: KeyboardEvent): void {
    const isMod = event.metaKey || event.ctrlKey;
    if (isMod && event.key.toLowerCase() === 'k') {
      event.preventDefault();
      this.focusTextarea();
    }
  }

  @HostListener('paste', ['$event'])
  handlePaste(event: ClipboardEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    const items = event.clipboardData?.items;
    if (!items) {
      return;
    }
    const files: File[] = [];
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (item.kind === 'file') {
        const file = item.getAsFile();
        if (file) {
          files.push(file);
        }
      }
    }
    if (files.length > 0) {
      event.preventDefault();
      this.addFiles(files);
    }
  }

  handleDragOver(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    if (event.dataTransfer) {
      event.dataTransfer.dropEffect = 'copy';
    }
  }

  handleDragEnter(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => n + 1);
  }

  handleDragLeave(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => Math.max(0, n - 1));
  }

  handleDrop(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.set(0);
    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.addFiles(Array.from(files));
    }
  }

  submit(): void {
    if (this.disabled()) {
      return;
    }

    const currentState = this.state();

    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }

    if (currentState === 'error') {
      this.retried.emit();
      return;
    }

    const event: PromptInputSubmitEvent = {
      value: this.value(),
      attachments: this.attachments(),
      preventDefault: () => {
        /* Consumer can short-circuit clearing/UI by calling this. */
      },
    };
    this.submitted.emit(event);
  }

  clear(): void {
    this.value.set('');
    this.attachments.set([]);
  }

  focusTextarea(): void {
    const textarea = this.elementRef.nativeElement.querySelector('textarea');
    textarea?.focus();
  }

  addFiles(files: readonly File[]): void {
    for (const file of files) {
      const error = this.validateFile(file);
      if (error) {
        this.attachmentError.emit(error);
        continue;
      }
      this.attachments.update((prev) => [...prev, toAttachmentData(file)]);
    }
  }

  /**
   * Remove an attachment by reference, by id, or by underlying File. The
   * three signatures let consumers match whatever they have in hand
   * (full object, just the id, or the original File from drag-drop).
   */
  removeAttachment(target: AttachmentData | string | File): void {
    this.attachments.update((prev) =>
      prev.filter((item) => {
        if (typeof target === 'string') return item.id !== target;
        if (target instanceof File) return item.file !== target;
        return item.id !== target.id;
      }),
    );
  }

  private validateFile(file: File): PromptInputAttachmentError | null {
    const accept = this.acceptAttachments();
    if (accept !== false && accept.length > 0) {
      const isAccepted = accept.some((pattern) => {
        if (pattern.endsWith('/*')) {
          return file.type.startsWith(pattern.slice(0, -1));
        }
        return file.type === pattern;
      });
      if (!isAccepted) {
        return {
          file,
          reason: 'invalid-mime',
          message: `MIME type "${file.type}" not accepted`,
        };
      }
    }

    if (file.size > this.maxAttachmentSize()) {
      const mb = (this.maxAttachmentSize() / (1024 * 1024)).toFixed(1);
      return {
        file,
        reason: 'too-large',
        message: `File "${file.name}" exceeds maximum size of ${mb} MB`,
      };
    }

    if (this.attachments().length >= this.maxAttachments()) {
      return {
        file,
        reason: 'max-count',
        message: `Maximum of ${this.maxAttachments()} attachments reached`,
      };
    }

    return null;
  }

  private handleEscape(): void {
    const currentState = this.state();
    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }
    this.clear();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * PromptInputBody — wraps the textarea row inside the composer.
 *
 * Mirrors React `PromptInputBody`, which renders with `display: contents` so the
 * textarea participates directly in the `PromptInput` flex column. The Header and
 * Footer are SIBLINGS of the Body, never nested inside it — nesting them inside a
 * `contents` element re-introduces the thin-bar render bug documented in
 * `docs/anatomy/assistant.md`.
 */
@Component({
  selector: 'prompt-input-body',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    'data-slot': 'prompt-input-body',
    class: 'contents',
  },
})
export class PromptInputBody {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

/**
 * PromptInputHeader — the top addon row of the composer.
 *
 * Mirrors React `PromptInputHeader` (an `InputGroupAddon align="block-start"`):
 * a wrapping flex row that hosts header affordances such as the "@ Add context"
 * mentions button and the Context token-usage trigger. Must be a SIBLING of
 * `<prompt-input-body>`, not nested inside it.
 */
/**
 * Base classes of the React `InputGroupAddon` (rx-forms) plus its
 * `block-start` alignment variant. Keep in lock-step with
 * `packages/rx-forms/src/lib/input-group/input-group.tsx`.
 */
const ADDON_BASE =
  "text-muted-foreground flex h-auto cursor-text select-none items-center justify-center gap-2 py-1.5 text-sm font-medium group-data-[disabled=true]/input-group:opacity-50 [&>kbd]:rounded-[calc(var(--radius)-5px)] [&>svg:not([class*='size-'])]:size-4";
const ADDON_BLOCK_START =
  '[.border-b]:pb-3 order-first w-full justify-start px-3 pt-3 group-has-[>input]/input-group:pt-2.5';

@Component({
  selector: 'prompt-input-header',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    'data-slot': 'prompt-input-header',
    'data-align': 'block-start',
    '[class]': 'hostClass()',
  },
})
export class PromptInputHeader {
  readonly class = input<string>('');
  protected readonly hostClass = computed(() =>
    cn(ADDON_BASE, ADDON_BLOCK_START, 'flex-wrap gap-1', this.class()),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

/**
 * PromptInputFooter — the bottom addon row of the composer (a.k.a. the toolbar).
 *
 * Mirrors React `PromptInputFooter` (an `InputGroupAddon align="block-end"`): a
 * spaced row that hosts the mode/model selects on the left and the web-search /
 * attach / speech / submit affordances on the right. Must be a SIBLING of
 * `<prompt-input-body>`, never nested inside it — see the `display:contents`
 * gotcha in `docs/anatomy/assistant.md`.
 */
/**
 * Base classes of the React `InputGroupAddon` (rx-forms) plus its
 * `block-end` alignment variant. Keep in lock-step with
 * `packages/rx-forms/src/lib/input-group/input-group.tsx`.
 */
const ADDON_BASE =
  "text-muted-foreground flex h-auto cursor-text select-none items-center justify-center gap-2 py-1.5 text-sm font-medium group-data-[disabled=true]/input-group:opacity-50 [&>kbd]:rounded-[calc(var(--radius)-5px)] [&>svg:not([class*='size-'])]:size-4";
const ADDON_BLOCK_END =
  '[.border-t]:pt-3 order-last w-full justify-start px-3 pb-3 group-has-[>input]/input-group:pb-2.5';

@Component({
  selector: 'prompt-input-footer',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    'data-slot': 'prompt-input-footer',
    'data-align': 'block-end',
    '[class]': 'hostClass()',
  },
})
export class PromptInputFooter {
  readonly class = input<string>('');
  protected readonly hostClass = computed(() =>
    cn(ADDON_BASE, ADDON_BLOCK_END, 'justify-between gap-1', this.class()),
  );
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  HostListener,
  inject,
  input,
  OnDestroy,
  ViewChild,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

import { PromptInput } from './prompt-input';

@Component({
  selector: 'prompt-input-textarea',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <textarea
      #textarea
      data-slot="input-group-control"
      [class]="textareaClass()"
      [value]="parent.value()"
      [disabled]="isDisabled()"
      [attr.aria-disabled]="isDisabled() ? 'true' : null"
      [attr.aria-label]="ariaLabel()"
      [placeholder]="placeholder()"
      [rows]="rows()"
      [attr.maxlength]="maxLength() ?? null"
      [attr.data-state]="parent.state()"
      aria-multiline="true"
      (input)="handleInput($event)"
    ></textarea>
  `,
  host: {
    // The textarea itself must be the flex child of the composer column
    // (React renders it as a direct InputGroup child).
    class: 'contents',
  },
})
export class PromptInputTextarea implements AfterViewInit, OnDestroy {
  protected readonly parent = inject(PromptInput);

  @ViewChild('textarea', { static: true })
  private readonly textareaRef!: ElementRef<HTMLTextAreaElement>;

  readonly placeholder = input<string>('Ask anything…');
  readonly rows = input<number>(1);
  readonly maxLength = input<number | null>(null);
  readonly ariaLabel = input<string>('Prompt');
  readonly maxHeightPx = input<number>(192); // 12rem default

  protected readonly isDisabled = (): boolean =>
    this.parent.disabled() || this.parent.state() === 'submitted';

  // React renders Textarea (rx-forms) + the rx-ai InputGroupTextarea and
  // PromptInputTextarea overrides. Keep the three strings in lock-step with
  // `packages/rx-forms/src/lib/textarea/textarea.tsx`,
  // `packages/rx-forms/src/lib/input-group/input-group.tsx` and
  // `packages/rx-ai/src/lib/prompt-input/prompt-input.tsx`.
  protected readonly textareaClass = () =>
    cn(
      'flex field-sizing-content min-h-16 w-full rounded-md border border-input bg-transparent px-3 py-2 text-base shadow-xs transition-[color,box-shadow] outline-none placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 md:text-sm dark:bg-input/30 dark:aria-invalid:ring-destructive/40',
      'flex-1 resize-none rounded-none border-0 bg-transparent py-3 shadow-none focus-visible:ring-0 dark:bg-transparent',
      'field-sizing-content max-h-48 min-h-16',
    );

  private resizeObserver?: ResizeObserver;

  ngAfterViewInit(): void {
    // With native `field-sizing: content` the CSS `min-h-16`/`max-h-48` pair
    // drives sizing (matching React); an inline height would freeze it.
    if (!this.hasFieldSizingSupport()) {
      this.applyMaxHeight();
      this.autoExpand(); // initial fit
    }
  }

  ngOnDestroy(): void {
    this.resizeObserver?.disconnect();
  }

  @HostListener('window:resize')
  onResize(): void {
    if (!this.hasFieldSizingSupport()) {
      this.autoExpand();
    }
  }

  handleInput(event: Event): void {
    const target = event.target as HTMLTextAreaElement;
    this.parent.value.set(target.value);
    if (!this.hasFieldSizingSupport()) {
      this.autoExpand();
    }
  }

  focus(): void {
    this.textareaRef.nativeElement.focus();
  }

  blur(): void {
    this.textareaRef.nativeElement.blur();
  }

  private applyMaxHeight(): void {
    const el = this.textareaRef.nativeElement;
    el.style.maxHeight = `${this.maxHeightPx()}px`;
  }

  private autoExpand(): void {
    const el = this.textareaRef.nativeElement;
    el.style.height = 'auto';
    const next = Math.min(el.scrollHeight, this.maxHeightPx());
    el.style.height = `${next}px`;
  }

  private hasFieldSizingSupport(): boolean {
    return (
      typeof CSS !== 'undefined' &&
      typeof CSS.supports === 'function' &&
      CSS.supports('field-sizing', 'content')
    );
  }
}

import { NgTemplateOutlet } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@gremorie/ng-overlays';

import { PromptInput } from './prompt-input';
import { PromptInputState } from './prompt-input.types';

const ICON_MAP: Record<PromptInputState, string> = {
  ready: 'M5 12h14M13 5l7 7-7 7',
  submitted: '', // spinner — rendered via SVG below
  streaming: 'M6 6h12v12H6z',
  error:
    'M12 9v4M12 17h.01M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z',
};

const LABEL_MAP: Record<PromptInputState, string> = {
  ready: 'Send message',
  submitted: 'Submitting',
  streaming: 'Stop generating',
  error: 'Retry',
};

// size-8 mirrors the React PromptInputSubmit default (InputGroupButton
// `icon-sm`), keeping both composers' send buttons the same footprint.
const submitVariants = cva(
  'inline-flex size-8 shrink-0 items-center justify-center rounded-md transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50',
  {
    variants: {
      state: {
        ready: 'bg-primary text-primary-foreground hover:bg-primary/90',
        submitted: 'bg-muted text-muted-foreground',
        streaming: 'bg-destructive/10 text-destructive hover:bg-destructive/20',
        error:
          'bg-destructive text-destructive-foreground hover:bg-destructive/90',
      },
    },
    defaultVariants: {
      state: 'ready',
    },
  },
);

@Component({
  selector: 'prompt-input-submit',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    NgTemplateOutlet,
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
  ],
  template: `
    @if (tooltip()) {
      <gn-tooltip-provider>
        <gn-tooltip>
          <gn-tooltip-trigger>
            <ng-container [ngTemplateOutlet]="btn" />
          </gn-tooltip-trigger>
          <gn-tooltip-content>{{ tooltip() }}</gn-tooltip-content>
        </gn-tooltip>
      </gn-tooltip-provider>
    } @else {
      <ng-container [ngTemplateOutlet]="btn" />
    }

    <ng-template #btn>
      <button
        type="button"
        [class]="buttonClass()"
        [attr.aria-label]="ariaLabel()"
        [attr.aria-busy]="isBusy() ? 'true' : null"
        [attr.data-state]="state()"
        [disabled]="isDisabled()"
        (click)="handleClick()"
      >
        <ng-content>
          @if (state() === 'submitted') {
            <svg
              class="size-4 animate-spin"
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <circle
                cx="12"
                cy="12"
                r="10"
                stroke="currentColor"
                stroke-width="2"
                stroke-linecap="round"
                stroke-dasharray="20 40"
              ></circle>
            </svg>
          } @else {
            <svg
              class="size-4"
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              stroke-width="2"
              stroke-linecap="round"
              stroke-linejoin="round"
              aria-hidden="true"
            >
              <path [attr.d]="iconPath()"></path>
            </svg>
          }
        </ng-content>
      </button>
    </ng-template>
  `,
})
export class PromptInputSubmit {
  protected readonly parent = inject(PromptInput);

  readonly disabled = input<boolean>(false);

  /**
   * Optional hover/focus tooltip. Mirrors React PromptInputSubmit `tooltip`:
   * when set, the button is wrapped in the styled gn-tooltip compound.
   */
  readonly tooltip = input<string | null | undefined>(null);

  protected readonly state = computed<PromptInputState>(() =>
    this.parent.state(),
  );

  protected readonly isBusy = computed(
    () => this.state() === 'submitted' || this.state() === 'streaming',
  );

  // Parity with React PromptInputSubmit: the button is NOT auto-disabled by an
  // empty input or the submitted state (the host decides what a click does), so
  // the ready button stays solid (not faded). Only an explicit `disabled` (own
  // or parent) disables it.
  protected readonly isDisabled = computed(
    () => this.disabled() || this.parent.disabled(),
  );

  protected readonly ariaLabel = computed(() => LABEL_MAP[this.state()]);
  protected readonly iconPath = computed(() => ICON_MAP[this.state()]);

  protected readonly buttonClass = computed(() =>
